#include <iostream>
#include <map>
#include <string>
#include <cctype>

bool check_dict_case(const std::map<std::string, std::string>& dict) {
    if (dict.empty()) {
        return false;
    }

    bool all_lower = true;
    bool all_upper = true;

    for (const auto& pair : dict) {
        const std::string& key = pair.first;
        if (!std::isalpha(key[0])) { // Check if the key is a string
            return false;
        }
        if (std::islower(key[0])) {
            all_upper = false;
        } else {
            all_lower = false;
        }
    }

    return all_lower || all_upper;
}

// Example usage
int main() {
    std::map<std::string, std::string> dict1 = {{"a", "apple"}, {"b", "banana"}};
    std::cout << check_dict_case(dict1) << std::endl; // should return true

    std::map<std::string, std::string> dict2 = {{"a", "apple"}, {"A", "banana"}, {"B", "banana"}};
    std::cout << check_dict_case(dict2) << std::endl; // should return false

    std::map<std::string, std::string> dict3 = {{"Name", "John"}, {"Age", "36"}, {"City", "Houston"}};
    std::cout << check_dict_case(dict3) << std::endl; // should return false

    std::map<std::string, std::string> dict4 = {{"STATE", "NC"}, {"ZIP", "12345"}};
    std::cout << check_dict_case(dict4) << std::endl; // should return true

    return 0;
}
