```java
public class CheckDictCase {
    public static int checkDictCase(Map<String, String> dict) {
        if (dict.isEmpty()) {
            return 0; // Return 0 for empty dictionary
        }

        boolean allLower = true;
        boolean allUpper = true;

        for (String key : dict.keySet()) {
            if (!(key instanceof String)) {
                return 0; // Return 0 if any key is not a string
            }
            if (Character.isLowerCase(key.charAt(0))) {
                allUpper = false;
            } else {
                allLower = false;
            }
        }

        return (allLower || allUpper) ? 1 : 0; // Return 1 for valid case, 0 otherwise
    }
}
